// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Log in with email and password
	// (POST /api/v1/auth/login)
	Login(ctx context.Context, request LoginRequestObject) (LoginResponseObject, error)
	// Get login configuration
	// (GET /api/v1/auth/login/config)
	GetLoginConfig(ctx context.Context, request GetLoginConfigRequestObject) (GetLoginConfigResponseObject, error)
	// Register a new user account
	// (POST /api/v1/auth/register)
	Register(ctx context.Context, request RegisterRequestObject) (RegisterResponseObject, error)
	// Request a password reset email
	// (POST /api/v1/auth/reset)
	ResetPassword(ctx context.Context, request ResetPasswordRequestObject) (ResetPasswordResponseObject, error)
	// List all Datei
	// (GET /api/v1/datei)
	ListDatei(ctx context.Context, request ListDateiRequestObject) (ListDateiResponseObject, error)
	// Create a new Datei
	// (POST /api/v1/datei)
	CreateDatei(ctx context.Context, request CreateDateiRequestObject) (CreateDateiResponseObject, error)
	// Delete a Datei
	// (DELETE /api/v1/datei/{id})
	DeleteDatei(ctx context.Context, request DeleteDateiRequestObject) (DeleteDateiResponseObject, error)
	// Update a Datei
	// (PATCH /api/v1/datei/{id})
	UpdateDatei(ctx context.Context, request UpdateDateiRequestObject) (UpdateDateiResponseObject, error)
	// Download a Datei
	// (GET /api/v1/datei/{id}/download)
	DownloadDatei(ctx context.Context, request DownloadDateiRequestObject) (DownloadDateiResponseObject, error)
	// Get the ancestor path of a Datei from root
	// (GET /api/v1/datei/{id}/path)
	GetDateiPath(ctx context.Context, request GetDateiPathRequestObject) (GetDateiPathResponseObject, error)
	// Get thumbnail for a Datei
	// (GET /api/v1/datei/{id}/thumbnail)
	GetDateiThumbnail(ctx context.Context, request GetDateiThumbnailRequestObject) (GetDateiThumbnailResponseObject, error)
	// List the authenticated user's links
	// (GET /api/v1/links)
	ListLinks(ctx context.Context, request ListLinksRequestObject) (ListLinksResponseObject, error)
	// Create a new public link
	// (POST /api/v1/links)
	CreateLink(ctx context.Context, request CreateLinkRequestObject) (CreateLinkResponseObject, error)
	// Revoke a link
	// (DELETE /api/v1/links/{id})
	RevokeLink(ctx context.Context, request RevokeLinkRequestObject) (RevokeLinkResponseObject, error)
	// Get a single link with its top-level dateien
	// (GET /api/v1/links/{id})
	GetLink(ctx context.Context, request GetLinkRequestObject) (GetLinkResponseObject, error)
	// Update a link
	// (PATCH /api/v1/links/{id})
	UpdateLink(ctx context.Context, request UpdateLinkRequestObject) (UpdateLinkResponseObject, error)
	// Add a datei to a link
	// (POST /api/v1/links/{id}/dateien)
	AddDateiToLink(ctx context.Context, request AddDateiToLinkRequestObject) (AddDateiToLinkResponseObject, error)
	// Remove a datei from a link
	// (DELETE /api/v1/links/{id}/dateien/{dateiId})
	RemoveDateiFromLink(ctx context.Context, request RemoveDateiFromLinkRequestObject) (RemoveDateiFromLinkResponseObject, error)
	// Generate a new access token, invalidating the old URL
	// (POST /api/v1/links/{id}/rotate)
	RotateLinkAccessToken(ctx context.Context, request RotateLinkAccessTokenRequestObject) (RotateLinkAccessTokenResponseObject, error)
	// List dateien shared via a public link
	// (GET /api/v1/public/links/{accessToken}/dateien)
	ListPublicLinkDateien(ctx context.Context, request ListPublicLinkDateienRequestObject) (ListPublicLinkDateienResponseObject, error)
	// Download a datei via a public link
	// (GET /api/v1/public/links/{accessToken}/dateien/{dateiId}/download)
	DownloadPublicLinkDatei(ctx context.Context, request DownloadPublicLinkDateiRequestObject) (DownloadPublicLinkDateiResponseObject, error)
	// List user emails
	// (GET /api/v1/settings/emails)
	ListEmails(ctx context.Context, request ListEmailsRequestObject) (ListEmailsResponseObject, error)
	// Add a new email
	// (POST /api/v1/settings/emails)
	AddEmail(ctx context.Context, request AddEmailRequestObject) (AddEmailResponseObject, error)
	// Remove a non-primary email
	// (DELETE /api/v1/settings/emails/{emailId})
	RemoveEmail(ctx context.Context, request RemoveEmailRequestObject) (RemoveEmailResponseObject, error)
	// Set an email as primary
	// (PATCH /api/v1/settings/emails/{emailId}/primary)
	SetPrimaryEmail(ctx context.Context, request SetPrimaryEmailRequestObject) (SetPrimaryEmailResponseObject, error)
	// Disable MFA
	// (POST /api/v1/settings/mfa/disable)
	DisableMFA(ctx context.Context, request DisableMFARequestObject) (DisableMFAResponseObject, error)
	// Enable MFA with TOTP code
	// (POST /api/v1/settings/mfa/enable)
	EnableMFA(ctx context.Context, request EnableMFARequestObject) (EnableMFAResponseObject, error)
	// Regenerate MFA recovery codes
	// (POST /api/v1/settings/mfa/recovery-codes/regenerate)
	RegenerateMFARecoveryCodes(ctx context.Context, request RegenerateMFARecoveryCodesRequestObject) (RegenerateMFARecoveryCodesResponseObject, error)
	// Get MFA recovery codes status
	// (GET /api/v1/settings/mfa/recovery-codes/status)
	GetMFARecoveryCodesStatus(ctx context.Context, request GetMFARecoveryCodesStatusRequestObject) (GetMFARecoveryCodesStatusResponseObject, error)
	// Initiate MFA setup
	// (POST /api/v1/settings/mfa/setup)
	SetupMFA(ctx context.Context, request SetupMFARequestObject) (SetupMFAResponseObject, error)
	// Set a new password using a password reset token
	// (POST /api/v1/settings/reset-password)
	ConfirmResetPassword(ctx context.Context, request ConfirmResetPasswordRequestObject) (ConfirmResetPasswordResponseObject, error)
	// Get the current user's profile
	// (GET /api/v1/settings/user)
	GetCurrentUser(ctx context.Context, request GetCurrentUserRequestObject) (GetCurrentUserResponseObject, error)
	// Update user name or password
	// (POST /api/v1/settings/user)
	UpdateUser(ctx context.Context, request UpdateUserRequestObject) (UpdateUserResponseObject, error)
	// Change user primary email
	// (PATCH /api/v1/settings/user/email)
	UpdateUserEmail(ctx context.Context, request UpdateUserEmailRequestObject) (UpdateUserEmailResponseObject, error)
	// Confirm email verification
	// (POST /api/v1/settings/verify/confirm)
	ConfirmEmailVerification(ctx context.Context, request ConfirmEmailVerificationRequestObject) (ConfirmEmailVerificationResponseObject, error)
	// Request an email verification link
	// (POST /api/v1/settings/verify/request)
	RequestEmailVerification(ctx context.Context, request RequestEmailVerificationRequestObject) (RequestEmailVerificationResponseObject, error)
	// List items in trash
	// (GET /api/v1/trash)
	ListTrash(ctx context.Context, request ListTrashRequestObject) (ListTrashResponseObject, error)
	// List the contents of a trashed directory
	// (GET /api/v1/trash/{dateiId}/children)
	ListTrashChildren(ctx context.Context, request ListTrashChildrenRequestObject) (ListTrashChildrenResponseObject, error)
	// Restore an item from trash
	// (POST /api/v1/trash/{dateiId}/restore)
	RestoreTrash(ctx context.Context, request RestoreTrashRequestObject) (RestoreTrashResponseObject, error)
}

